import React, { useState } from 'react';
import { aiService } from '../services/aiService';

// Page: AI Chatbot
// Maintains a local conversation history and sends it to the backend for multi-turn responses.
const AIChatbot = () => {
  const systemPrompt = `You are an expert in freelance client acquisition, proposal writing, pricing strategy (Indian ₹ market), tech stack advice, and client objection handling.`;
  const [conversation, setConversation] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const sendMessage = async () => {
    if (!input.trim()) return;
    const userMsg = { role: 'user', content: input };
    const newConv = [...conversation, userMsg];
    setConversation(newConv);
    setInput('');
    setLoading(true);
    try {
      const res = await aiService.chat(systemPrompt, newConv);
      const assistantText = res.data || res;
      const assistantMsg = { role: 'assistant', content: assistantText };
      setConversation((c) => [...c, assistantMsg]);
    } catch (err) {
      console.error(err);
      alert('AI request failed');
    }
    setLoading(false);
  };

  const quickReplies = [
    'How to price a 3-month web app project?',
    'Write a short cold outreach for SaaS startups in India',
    'How to handle scope creep?',
  ];

  return (
    <div>
      <h2>AI Assistant</h2>
      <div style={{ border: '1px solid #ddd', padding: 10, height: 400, overflow: 'auto' }}>
        {conversation.map((m, i) => (
          <div key={i} style={{ margin: 8 }}>
            <strong>{m.role === 'user' ? 'You' : 'Assistant'}:</strong>
            <div>{m.content}</div>
          </div>
        ))}
      </div>

      <div style={{ marginTop: 10 }}>
        {quickReplies.map((q) => (
          <button key={q} style={{ marginRight: 8 }} onClick={() => { setInput(q); }}>
            {q}
          </button>
        ))}
      </div>

      <div style={{ marginTop: 10 }}>
        <input value={input} onChange={(e) => setInput(e.target.value)} placeholder="Ask the assistant..." style={{ width: '70%' }} />
        <button onClick={sendMessage} disabled={loading}>{loading ? 'Thinking...' : 'Send'}</button>
      </div>
    </div>
  );
};

export default AIChatbot;
